78	    const {
79	      prompt,
80	      n = 1,
81	      size,
82	      aspectRatio = '1:1',
83	      seed,
84	      providerOptions,
85	      headers,
86	      abortSignal,
87	      files,
88	      mask,
89	    } = options;
90	    const warnings: Array<SharedV3Warning> = [];
