import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  combineHeaders,
  createJsonResponseHandler,
  postJsonToApi,
} from '@ai-sdk/provider-utils';
import { PixelArtConfig } from './pixelart-config';
import { pixelArtFailedResponseHandler } from './pixelart-error';
import { pixelArtImageResponseSchema } from './pixelart-image-api';

export type PixelArtImageModelId =
  | 'pixelart-v1'
  | 'pixelart-v2'
  | 'pixelart-retro'
  | (string & {});

/**
 * Settings for PixelArt image generation models.
 * Pass these via `providerOptions: { pixelart: { ... } }`.
 */
export interface PixelArtImageSettings {
  /**
   * The desired output image size (e.g. "512x512", "1024x1024").
   */
  size?: string;

  /**
   * The pixel-art rendering style.
   * - "pixel"  – clean pixel-art aesthetic (default)
   * - "retro"  – retro/CRT scanline look
   * - "8bit"   – classic 8-bit palette
   */
  style?: 'pixel' | 'retro' | '8bit';

  /**
   * Pixel density: number of logical pixels per output pixel.
   * Higher values produce coarser, blockier results.
   * Must be a positive integer (e.g. 1–16).
   */
  pixelDensity?: number;
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    // PixelArt API does not support aspect ratio — use `size` instead
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspect ratio. Use `size` in providerOptions instead.',
      });
    }

    // PixelArt API does not support image editing (files/mask)
    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    // Extract PixelArt-specific provider options
    const pixelArtOptions =
      (providerOptions?.pixelart as PixelArtImageSettings | undefined) ?? {};

    const { value: response, responseHeaders } = await postJsonToApi({
      url: this.config.url({
        path: '/images/generate',
        modelId: this.modelId,
      }),
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        // Standard size from call options, overridden by provider option if present
        ...(pixelArtOptions.size != null
          ? { size: pixelArtOptions.size }
          : size != null
            ? { size }
            : {}),
        ...(pixelArtOptions.style != null
          ? { style: pixelArtOptions.style }
          : {}),
        ...(pixelArtOptions.pixelDensity != null
          ? { pixel_density: pixelArtOptions.pixelDensity }
          : {}),
        ...(seed != null ? { seed } : {}),
      },
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      usage:
        response.usage != null
          ? {
              inputTokens: response.usage.input_tokens ?? undefined,
              outputTokens: response.usage.output_tokens ?? undefined,
              totalTokens: response.usage.total_tokens ?? undefined,
            }
          : undefined,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
    };
  }
}

