import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import {
  FetchFunction,
  loadApiKey,
  loadOptionalSetting,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import {
  PixelArtImageModel,
  PixelArtImageModelId,
} from './pixelart-image-model';
import { VERSION } from './version';

export interface PixelArtProvider extends ProviderV3 {
  /**
   * Creates a PixelArt image generation model.
   */
  (modelId: PixelArtImageModelId): ImageModelV3;

  /**
   * Creates a PixelArt image generation model.
   */
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;

  /**
   * Creates a PixelArt image generation model.
   */
  image(modelId: PixelArtImageModelId): ImageModelV3;
}

export interface PixelArtProviderSettings {
  /**
   * Base URL for the PixelArt API. Defaults to "https://api.pixelart.ai/v1".
   */
  baseURL?: string;

  /**
   * API key for authenticating requests.
   * Falls back to the PIXELART_API_KEY environment variable.
   */
  apiKey?: string;

  /**
   * Custom headers to include in every request.
   */
  headers?: Record<string, string>;

  /**
   * Custom fetch implementation. Useful as middleware for intercepting
   * requests or for providing a test double.
   */
  fetch?: FetchFunction;
}

/**
 * Create a PixelArt provider instance.
 */
export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL =
    withoutTrailingSlash(
      loadOptionalSetting({
        settingValue: options.baseURL,
        environmentVariableName: 'PIXELART_BASE_URL',
      }),
    ) ?? 'https://api.pixelart.ai/v1';

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const provider = function (modelId: PixelArtImageModelId) {
    if (new.target) {
      throw new Error(
        'The PixelArt model function cannot be called with the new keyword.',
      );
    }
    return createImageModel(modelId);
  };

  provider.specificationVersion = 'v3' as const;

  provider.image = createImageModel;
  provider.imageModel = createImageModel;

  // PixelArt is image-only — language and embedding models are not supported.
  provider.languageModel = (modelId: string) => {
    throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
  };
  provider.embeddingModel = (modelId: string) => {
    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
  };

  return provider as PixelArtProvider;
}

/**
 * Default PixelArt provider instance.
 */
export const pixelart = createPixelArt();

