 * Pass these via `providerOptions: { pixelart: { ... } }`.
 */
export interface PixelArtImageSettings {
    /**
     * The desired output image size (e.g. "512x512", "1024x1024").
     */
    size?: string;
    /**
     * The pixel-art rendering style.
     * - "pixel"  – clean pixel-art aesthetic (default)
     * - "retro"  – retro/CRT scanline look
     * - "8bit"   – classic 8-bit palette
     */
    style?: 'pixel' | 'retro' | '8bit';
    /**
     * Pixel density: number of logical pixels per output pixel.
     * Higher values produce coarser, blockier results.
     * Must be a positive integer (e.g. 1–16).
     */
    pixelDensity?: number;
}
